import React, { useEffect, useState } from 'react';
import { Navigate, Outlet } from 'react-router-dom';
import Header from '../1_Header/Header';
import DashboardSidebar from './DashboardSidebar';
import LoadingSpinner from '../9_Common/LoadingSpinner';
import { useAuth } from '../../hooks/useAuth';
import './Layout.css';

export default function DashboardLayout() {
  const { isLoggedIn, isAdmin, loading } = useAuth();
  const [sidebarOpen, setSidebarOpen] = useState(false);

  useEffect(() => {
    document.body.style.overflow = sidebarOpen && window.innerWidth <= 1024 ? 'hidden' : '';
    return () => {
      document.body.style.overflow = '';
    };
  }, [sidebarOpen]);

  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth > 1024) setSidebarOpen(false);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  if (loading) {
    return (
      <div className="matey-dashboard-loading">
        <LoadingSpinner size="lg" label="대시보드를 준비하고 있어요..." />
      </div>
    );
  }

  if (!isLoggedIn) {
    return <Navigate to="/login" replace />;
  }

  return (
    <div className="matey-dashboard-layout">
      <Header />

      <div className="matey-dashboard-layout__body">
        <DashboardSidebar
          isAdmin={isAdmin}
          isOpen={sidebarOpen}
          onClose={() => setSidebarOpen(false)}
        />

        <main className="matey-dashboard-layout__main">
          <div className="matey-dashboard-layout__toolbar">
            <button
              type="button"
              className="matey-dashboard-layout__menu-btn"
              onClick={() => setSidebarOpen(true)}
            >
              <span />
              <span />
              <span />
            </button>

            <div className="matey-dashboard-layout__toolbar-copy">
              <strong>Dashboard Menu</strong>
              <span>캐릭터 중심 관리 화면</span>
            </div>
          </div>

          <div className="matey-dashboard-layout__inner">
            <Outlet />
          </div>
        </main>
      </div>
    </div>
  );
}
